#include <bits/stdc++.h>
using namespace std;
long long a[21][21],n,ans;
unordered_map<long long,long long>m[21];
void s0(long long x,long long y,long long v){
	v^=a[x][y];
	if(x+y==n+1){
		m[x][v]++;
		return ;
	}
	s0(x+1,y,v);
	s0(x,y+1,v);
}
void s1(long long x,long long y,long long v){
	if(x+y==n+1){
		ans+=m[x][v];
		return;
	}
	v^=a[x][y];
	s1(x-1,y,v);
	s1(x,y-1,v);
}
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			cin>>a[i][j];
		}
	}
	s0(1,1,0);
	s1(n,n,0);
	cout<<ans;
	return 0;
}
